/**
 * 🤖 AI Chat Service (Client-side)
 *
 * Serviço para comunicação com a API de chat IA.
 * Gerencia envio de mensagens, ações rápidas e parsing de respostas.
 *
 * @module chat-service
 */

// ============================================================================
// TYPES
// ============================================================================

/** Mensagem no chat */
export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

/** Sugestão de IA */
export interface AISuggestion {
  type: 'script' | 'edit' | 'effect' | 'music' | 'color' | 'visual' | 'optimization';
  title: string;
  description: string;
  confidence: number;
  data?: Record<string, unknown>;
}

/** Contexto do projeto para enriquecer o prompt */
export interface ProjectContext {
  tracks?: number;
  clips?: number;
  duration?: number;
  currentTime?: number;
  slideTexts?: string[];
  projectTitle?: string;
}

/** Resposta da API de chat */
export interface ChatApiResponse {
  success: boolean;
  message: string;
  suggestions: AISuggestion[];
  error?: string;
}

/** Ações rápidas disponíveis */
export type QuickAction =
  | 'generate_script'
  | 'rewrite'
  | 'expand'
  | 'summarize'
  | 'translate_en'
  | 'translate_pt'
  | 'improve_tone'
  | 'add_examples';

/** Definição de ação rápida */
export interface QuickActionDef {
  id: QuickAction;
  label: string;
  icon: string;
  promptTemplate: string;
  requiresSelection: boolean;
}

