// ============================================================================
// SERVICE FUNCTIONS
// ============================================================================

/** Gera um ID único para mensagens */
export function generateMessageId(): string {
  return `msg_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
}

/** Cria uma mensagem de chat */
export function createChatMessage(
  role: ChatMessage['role'],
  content: string,
  metadata?: Record<string, unknown>,
): ChatMessage {
  return {
    id: generateMessageId(),
    role,
    content,
    timestamp: new Date(),
    metadata,
  };
}

/** Prepara o prompt de uma ação rápida substituindo {selection} */
export function buildQuickActionPrompt(
  actionId: QuickAction,
  selectedText?: string,
): string | null {
  const action = QUICK_ACTIONS.find((a) => a.id === actionId);
  if (!action) return null;

  if (action.requiresSelection && !selectedText?.trim()) {
    return null;
  }

  return action.promptTemplate.replace('{selection}', selectedText || '');
}

/** Converte ChatMessage[] para o formato esperado pela API (history) */
export function messagesToApiHistory(
  messages: ChatMessage[],
  maxMessages: number = 20,
): Array<{ role: 'user' | 'assistant' | 'system'; content: string }> {
  return messages
    .filter((m) => m.role !== 'system')
    .slice(-maxMessages)
    .map((m) => ({
      role: m.role,
      content: m.content,
    }));
}

/**
 * Envia uma mensagem para a API de chat IA.
 * 
 * @param message - Texto da mensagem do usuário
 * @param history - Histórico de mensagens anteriores
 * @param context - Contexto do projeto (slides, duração, etc.)
 * @param projectId - ID do projeto (opcional)
 * @returns Resposta da API com texto e sugestões
 */
export async function sendChatMessage(
  message: string,
  history: ChatMessage[],
  context?: ProjectContext,
  projectId?: string,
): Promise<ChatApiResponse> {
  try {
    const response = await fetch('/api/ai/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        message,
        projectId,
        context: context
          ? {
              tracks: context.tracks,
              clips: context.clips,
              duration: context.duration,
              currentTime: context.currentTime,
            }
          : undefined,
        history: messagesToApiHistory(history),
      }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      const errorMessage =
        (errorData as Record<string, unknown>).error as string ||
        `Erro ao processar a mensagem (${response.status})`;

      return {
        success: false,
        message: '',
        suggestions: [],
        error: errorMessage,
      };
    }

    const data: unknown = await response.json();
    const typedData = data as Record<string, unknown>;

    return {
      success: typedData.success === true,
      message: (typedData.message as string) || '',
      suggestions: Array.isArray(typedData.suggestions)
        ? (typedData.suggestions as AISuggestion[])
        : [],
    };
  } catch (error: unknown) {
    return {
      success: false,
      message: '',
      suggestions: [],
      error: error instanceof Error ? error.message : 'Erro de rede',
    };
  }
}

/**
 * Extrai blocos de código de uma resposta markdown.
 * Útil para sugestões de código que podem ser aplicadas.
 */
export function extractCodeBlocks(
  content: string,
): Array<{ language: string; code: string }> {
  const blocks: Array<{ language: string; code: string }> = [];
  const regex = /```(\w*)\n([\s\S]*?)```/g;
  let match: RegExpExecArray | null;

  while ((match = regex.exec(content)) !== null) {
    blocks.push({
      language: match[1] || 'text',
      code: match[2].trim(),
    });
  }

  return blocks;
}

/**
 * Verifica se o conteúdo da mensagem contém texto aplicável a um slide.
 * Texto que começa com aspas, bullets, ou blocos formatados é considerado aplicável.
 */
export function isApplicableContent(content: string): boolean {
  const trimmed = content.trim();
  if (!trimmed) return false;

  // Has code blocks
  if (/```[\s\S]*```/.test(trimmed)) return true;

  // Has quoted text
  if (/^[">]/.test(trimmed)) return true;

  // Has bullet points or numbered lists
  if (/^[-•*]\s/m.test(trimmed) || /^\d+\.\s/m.test(trimmed)) return true;

  // Longer content is generally applicable
  if (trimmed.length > 100) return true;

  return false;
}

/**
 * Extrai o texto "aplicável" de uma resposta (remove prefixos como "Aqui está:", etc.)
 */
export function extractApplicableText(content: string): string {
  // Remove common prefixes
  let text = content
    .replace(/^(Aqui está|Segue|Veja|Confira|Sugiro|Sugestão|Resultado)[:!]\s*/i, '')
    .replace(/^(Here's|Here is|Below is|Suggested)[:!]\s*/i, '')
    .trim();

  // Extract code blocks if present
  const codeBlocks = extractCodeBlocks(text);
  if (codeBlocks.length > 0) {
    return codeBlocks.map((b) => b.code).join('\n\n');
  }

  // Remove markdown bold/italic but keep content
  text = text.replace(/\*{1,2}([^*]+)\*{1,2}/g, '$1');

  return text;
}

/** Estima o tempo de espera da API em ms (heurística) */
export function estimateResponseTime(messageLength: number, historyLength: number): number {
  const base = 2000; // 2s base
  const perChar = 2; // 2ms per char
  const perHistory = 200; // 200ms per history message
  return base + messageLength * perChar + historyLength * perHistory;
}

/** Formata duração em formato legível (ex: "2min 30s") */
export function formatEstimatedTime(ms: number): string {
  if (ms < 1000) return 'menos de 1s';
  const seconds = Math.round(ms / 1000);
  if (seconds < 60) return `~${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  if (remainingSeconds === 0) return `~${minutes}min`;
  return `~${minutes}min ${remainingSeconds}s`;
}
